CREATE TABLE policies_to_users
(
	id serial,
	policy_id integer DEFAULT NULL,
	user_id integer NOT NULL,

	CONSTRAINT pk_policies_to_users PRIMARY KEY (id)
	, CONSTRAINT fk_policies_to_users_to_user FOREIGN KEY (user_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_policies_to_users_to_policies FOREIGN KEY (policy_id) REFERENCES policies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_policies_to_users_to_user ON policies_to_users (user_id);
CREATE INDEX i_policies_to_users_policy ON policies_to_users (policy_id);

CREATE TABLE policies_to_roles
(
	id serial,
	policy_id integer DEFAULT NULL,
	role_id integer NOT NULL,

	CONSTRAINT pk_policies_to_roles PRIMARY KEY (id)
	, CONSTRAINT fk_policies_to_roles_to_role FOREIGN KEY (role_id) REFERENCES roles (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_policies_to_roles_to_policies FOREIGN KEY (policy_id) REFERENCES policies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_policies_to_roles_to_role ON policies_to_roles (role_id);
CREATE INDEX i_policies_to_roles_policy ON policies_to_roles (policy_id);
